class Solution {
public:
    int closestToTarget(vector<int>& arr, int target) {
        int n = arr.size();
        set<int> s;
        int res = INT_MAX;
        for (int i = 0; i < n; i++) {
            set<int> t;
            t.insert(arr[i]);
            for (auto x : s) {
                t.insert(x & arr[i]);
            }
            s = t;
            for (auto x : s) {
                res = min(res, abs(x - target));
            }
        }
        return res;
    }
};
